module RefModule(
    input clk,
    input rst,
    input load,
    input [3:0] data_in,

    output reg [3:0] data_out
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk) begin
        if (rst)
            data_out <= 4'b0000;
        else if (load)
            data_out <= data_in;
        else
            data_out <= {1'b0, data_out[3:1]};
    end
endmodule
